import{_ as s,o as n,c as i,a6 as r,cL as e,cM as p,cN as l,cO as c,cP as h,cQ as m,ah as d,cR as g,cC as u,cS as w,cT as y,nm as f,nn as b,no as v,np as _,nq as k,ee as P,nr as C,ns as T,nt as Y,mj as A,mk as S,ml as x,nu as O,mm as R,mn as I,nv as $,nw as F,bg as V,mK as B,mL as D,mM as L,bN as M,lP as a,mN as N,mO as E,mP as H,mQ as K,mR as U,mS as q,mT as z,mU as W,mV as j,mW as J,lM as o,mX as Q,bi as G,bh as Z,mY as X,mZ as tt,m_ as et,mo as at,mp as ot,nx as st,mq as nt,mr as it,ny as rt,nz as pt,nA as lt,nB as ct,mC as ht,mD as mt,mE as dt,mF as gt,mG as ut,mH as wt,lK as yt,lL as ft,lN as bt,mI as vt,mJ as _t,lS as kt,cn as Pt,nC as Ct}from"./chunks/framework.UYVGz2W_.js";const $t=JSON.parse('{"title":"Status, publish and review","description":"","frontmatter":{},"headers":[],"relativePath":"status-publish-review/index.md","filePath":"status-publish-review/index.md"}'),Tt={name:"status-publish-review/index.md"};function Yt(At,t,St,xt,Ot,Rt){return n(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="status-publish-and-review" tabindex="-1">Status, publish and review <a class="header-anchor" href="#status-publish-and-review" aria-label="Permalink to “Status, publish and review”">​</a></h1><h2 id="publish-a-concept" tabindex="-1">Publish a Concept <a class="header-anchor" href="#publish-a-concept" aria-label="Permalink to “Publish a Concept”">​</a></h2><p>To publish a <strong>Concept</strong>, go to the <strong>Concept</strong> page with the navigation menu.</p><p><img src="'+e+'" alt="Concept Menu"></p><p>To upload a concept, click the <strong>Add a new reference to concepts</strong> button.</p><p>You can upload one or several concepts at the same time.</p><p><img src="'+p+'" alt="Concept empty page"></p><p>Once you upload your previews, the concept page will look like this.</p><p><img src="'+l+'" alt="Concept filled page"></p><p>You can interact with the concept in two ways: click on the picture to see an enlarged view. The second is to click on the status part to open the <strong>Comment Panel</strong> on the right.</p><p>You have two options on the comment panel: link a concept with an existing asset or delete the concept. You can also comment and change the status of the asset.</p><p>The idea is to have one version per <strong>Concept</strong>. If it&#39;s not approved, you need to upload a new concept, not to have multiple versions of the same concept.</p><p>One concept is one task.</p><p><img src="'+c+'" alt="Concept options"></p><h2 id="link-a-concept-to-an-asset" tabindex="-1">Link a Concept to an Asset <a class="header-anchor" href="#link-a-concept-to-an-asset" aria-label="Permalink to “Link a Concept to an Asset”">​</a></h2><p>Once concepts are uploaded, you can link them to the assets.</p><p>You can see the links on the status part of the assets.</p><p>Click on the status part of the concept; it will open the comment panel on the right.</p><p><img src="'+h+'" alt="Concept Comment Panel"></p><p>On the comment panel, you have two options on top of the panel: Link a concept to an asset and delete the concept.</p><p>To link an asset, click on the <strong>Link</strong> <img src="'+m+'" alt="Link button"> button.</p><p>Kitsu will display all the <strong>Assets</strong> available to link with the concept uploaded.</p><p>On top of the comment panel, Kitsu will list the linked assets. For now, there are <strong>No Links</strong>.</p><p><img src="'+d+'" alt="Concept link"></p><p>To link an asset, you have to click on it. You will see the name of the assets linked on the top of the screen, but also under the preview of the concept.</p><p><img src="'+g+'" alt="Concept asset linked"></p><p>Once a concept is linked to an asset, you can see the concepts on the detail page of an asset.</p><p>Return to the asset page, and click on the asset name you want to see the concept.</p><p><img src="'+u+'" alt="Detail asset page"></p><p>Per default, the casting detail is displayed on the second part of the screen. Use the dropdown menu to choose the concept.</p><p><img src="'+w+'" alt="asset detail concept"></p><p>Once in the concept section, you will see all the concepts created for this asset. You can filter them per status.</p><p><img src="'+y+'" alt="asset detail concept list"></p><h2 id="change-status-and-add-a-comment" tabindex="-1">Change Status and Add a Comment <a class="header-anchor" href="#change-status-and-add-a-comment" aria-label="Permalink to “Change Status and Add a Comment”">​</a></h2><p>To change the status of a task and write a comment, you need to click on the status of the task.</p><p><img src="'+f+'" alt="Shot status"></p><p>It makes a panel appear on the right, and here, you can write a comment, change the status, and attach a file.</p><p><img src="'+b+'" alt="Comment Panel"></p><p>The <strong>Commen Panel</strong> is split into 2 tabs :</p><ul><li>POST COMMENT</li><li>PUBLISH REVISION</li></ul><p>To change the <strong>Status</strong>, stay in <strong>POST COMMENT</strong> tab.</p><p>The comment uses the <strong>Markdown</strong> language. If you need specific syntax, feel free to look at the markdown guide website: <a href="https://www.markdownguide.org/basic-syntax/" target="_blank" rel="noreferrer">https://www.markdownguide.org/basic-syntax/</a></p><p>On the <strong>Leave a Comment...</strong> section, you can <strong>tag</strong> someone on the team in the comments. Type the <code>@</code>and it opens a sub-menu with the list of the team.</p><p><img src="'+v+'" alt="Tag someone"></p><p>You can also <strong>tag</strong> a full department by typing &#39;@&#39; and the department&#39;s name.</p><p><img src="'+_+'" alt="Tag department"></p><p>You can add a <strong>checklist</strong> to your comments.</p><p>You need to click on the <strong>Add checklist</strong> button, and the first item of the checklist appears.</p><p><img src="'+k+'" alt="add checklist"></p><p>Type your comments, hit the <strong>Enter</strong> key to add another line to your checklist, or click the <strong>Add Checklist</strong> button again.</p><p><img src="'+P+'" alt="checklist"></p><p>Besides your comment, you can also attach a file as a picture. Click on the <strong>Add attachment</strong> button.</p><p><img src="'+C+'" alt="Add Attachment Simple"></p><p>Select a <strong>file from your hard drive</strong> or past a <strong>screenshot</strong> here.</p><p><img src="'+T+'" alt="Attachment snapshot"></p><p>Validate the attachment by clicking on <strong>Add file as attachment</strong>.</p><p>Then select the <strong>Status</strong> that you need on the dropdown menu.</p><p><img src="'+Y+'" alt="Status List"></p><p>Then click the <strong>Post</strong> button to post it to the world.</p><h2 id="publish-a-preview-as-a-version" tabindex="-1">Publish a Preview as a Version <a class="header-anchor" href="#publish-a-preview-as-a-version" aria-label="Permalink to “Publish a Preview as a Version”">​</a></h2><p>To publish a preview, picture, or video, select the <strong>PUBLISH REVISION</strong> tab on the comment panel of the task.</p><p>Kitsu will automatically switch to the <strong>Publish Revision</strong> tab when you use status with the option <strong>IS FEEDBACK REQUEST</strong>, like the <strong>WFA</strong> Status.</p><p><img src="'+A+'" alt="Publish Revision"></p><p>You can add one or several previews to any comments. It can be a picture (<code>.png</code>, <code>.jpg</code>, <code>.jpeg</code>, <code>.gif</code>), a video (<code>.mp4</code>, <code>.mov</code>, <code>.wmv</code>), or an <code>.glb</code> file. You can review all the previews from the browser or mix everything.</p><p>For the <code>.glb</code> file you can also review it as wireframe, or add a <code>.HDR</code> file to check the lighting. Other files like <code>.pdf</code>, <code>.zip</code>, <code>.rar</code>, <code>.ma</code>, or <code>.mb</code>, however, need to be downloaded to be reviewed.</p><p>Then, click on the <strong>Add preview revision to publish</strong> button. The explorer opens and lets you choose your file or several files.</p><p><img src="'+S+'" alt="attach preview"></p><p>You can also <strong>copy-paste a screenshot</strong> to this screen.</p><p>You will see a preview of the attached files.</p><p><img src="'+x+'" alt="attach preview filled"></p><p>Once your file is selected, you will see its name near the <strong>Attach preview</strong> button.</p><p><img src="'+O+'" alt="attach preview confirmed"></p><p>You can also <strong>drag &amp; drop</strong> the file in the comment section.</p><p><img src="'+R+'" alt="attach preview drag drop"></p><p>On top of your preview, you can add a <strong>Comment</strong>.</p><p>Click the <strong>Leave a Comment</strong> button to unfold the comment section.</p><p><img src="'+I+'" alt="Add a comment to a Publish"></p><p>You can select your status and publish your preview with the <strong>Post</strong> Button.</p><h2 id="add-a-thumbnail" tabindex="-1">Add a Thumbnail <a class="header-anchor" href="#add-a-thumbnail" aria-label="Permalink to “Add a Thumbnail”">​</a></h2><p>To define a preview as a thumbnail, the preview MUST have been uploaded as a revision.</p><p>To publish a preview, picture, or video, select the <strong>PUBLISH REVISION</strong> tab on the comment panel of the task.</p><p>You can use the preview as a <strong>thumbnail</strong> on the asset or shot task. It helps to recognize the assets/shots on the main pages. On the list page, click on the status you want, then on the right panel, click the <strong>Preview</strong> button (1).</p><p><img src="'+$+'" alt="Thumbnail Button"></p><p>Once you have clicked on the button, you can choose if you want to pick the first or any frame; once the frame is selected, you see the thumbnail appear, and the button turns gray.</p><p><img src="'+F+'" alt="thumbnail applied"></p><h2 id="perform-a-review" tabindex="-1">Perform a Review <a class="header-anchor" href="#perform-a-review" aria-label="Permalink to “Perform a Review”">​</a></h2><p>When an artist needs a <strong>review</strong>, he changes the status of his task, too <img src="'+V+'" alt="wfa">.</p><p>Click on status to open the right panel and start the review.</p><p>You can watch the version from the right panel, enlarge it by grabbing the side of the panel, or even go fullscreen <img src="'+B+'" alt="Fullscreen">.</p><p><img src="'+D+'" alt="review on global page"></p><p>For the 3D file (<code>.glb</code> file) you can also review it as wireframe, or add a <code>.HDR</code> file to check the lighting.</p><p>You can move around the 3d file with a drag and move with your cursor, and zoom in or out with the scroll.</p><p><img src="'+L+'" alt="review 3d wireframe"></p><p><img src="'+M+'" alt="Preview background example"></p><p>You can draw directly on the preview with the <strong>Pencil</strong> tool and select a color <img src="'+a+'" alt="Pencil">.</p><p><img src="'+N+'" alt="review drawing"></p><p>You can also add <strong>text</strong> on the frame.</p><p><img src="'+E+'" alt="review drawing text"></p><p>If you need to see the preview without your comment, <strong>hide your annotation</strong>, you can click on the <strong>Fountain Pen</strong> button. <img src="'+H+'" alt="Hide Annotation"></p><p>You can tag a frame (whatever version you are in), type the <code>@</code>and it opens a sub-menu with the team list, and start typing <strong>frame</strong>.</p><p><img src="'+K+'" alt="Tag a frame"></p><p>You can also export your drawings on each frame by attaching the <strong>screenshots as attachments</strong>.</p><p>Click on the <strong>Add attachment</strong> button.</p><p><img src="'+U+'" alt="attachment"></p><p>You can also choose to <strong>Attach snapshots from your annotation</strong> on the attachment option.</p><p><img src="'+q+'" alt="Attachment snapshot"></p><p>Once you click the button, Kitsu will grab all the frames with annotation and display the result. You can publish them with <strong>Confirm</strong>.</p><p><img src="'+z+'" alt="Attachment snapshot detail"></p><p>If you need to delete your line, click the <strong>pencil</strong> icon again, and the cursor changes to a multi-directional cross <img src="'+W+'" alt="Pencil">, and then you can select your line and move it around.</p><p><img src="'+j+'" alt="review drawing"></p><p>Select the line with the directional cross, then press the <strong>delete</strong> icon <img src="'+J+'" alt="Delete line"></p><p>If you go into <strong>Full-Screen</strong>, you can compare two task types or versions side by side when you click on the <strong>Compare</strong> button <img src="'+o+'" alt="compare button">.</p><p><img src="'+Q+'" alt="compare button"></p><p>From there, you can change the status too<img src="'+G+'" alt="Retake"> if you want the Artist to perform some changes.</p><p>Alternatively, you can change it to <img src="'+Z+'" alt="Done"> to notify the Artist that his work is approved.</p><h2 id="review-a-concept" tabindex="-1">Review a Concept <a class="header-anchor" href="#review-a-concept" aria-label="Permalink to “Review a Concept”">​</a></h2><p>Once your artists upload the concept, you can review it with the supervisor or the director.</p><p>To review the concept, you use the navigation menu at the top of the screen and select the concept page.</p><p><img src="'+e+'" alt="Menu concept"></p><p>You can see all the concepts uploaded, the status, assignation, and linked assets.</p><p><img src="'+X+'" alt="Ccncept filled status"></p><p>To review a concept, click the status part to open the comment panel. You can enlarge the comment panel or go fullscreen.</p><p>Then, write a comment, select the status <strong>Approved</strong> or <strong>Rejected</strong>, and validate with the <strong>Post</strong> button.</p><p><img src="'+tt+'" alt="Ccncept status comment"></p><p>You can filter the page with the <strong>Status</strong> filter to display all the <strong>Neutral</strong> status concepts.</p><p><img src="'+et+'" alt="Ccncept status filter"></p><p>You can also filter per artist and change the order sort.</p><h2 id="add-multiple-previews-as-one-version" tabindex="-1">Add Multiple Previews as one Version <a class="header-anchor" href="#add-multiple-previews-as-one-version" aria-label="Permalink to “Add Multiple Previews as one Version”">​</a></h2><p>You can add multiple images simultaneously, or once you have uploaded an image, you can add another one.</p><p><img src="'+at+'" alt="attach preview drag drop"></p><p>The <strong>Add preview</strong> pop-up asks you to choose a file.</p><p>You can navigate through the pictures uploaded.</p><p>You can change the preview order by clicking the number and then dragging and dropping them.</p><p><img src="'+ot+'" alt="preview drag drop"></p><p>To delete an additional preview, you need to enlarge the comment panel by dragging it and clicking on the number of versions.</p><p><img src="'+st+'" alt="enlarge comment section"></p><p>And then click on the <img src="'+nt+'" alt="delete button"></p><p><img src="'+it+'" alt="enlarge comment section delete"></p><h2 id="change-status-per-batch" tabindex="-1">Change Status per Batch <a class="header-anchor" href="#change-status-per-batch" aria-label="Permalink to “Change Status per Batch”">​</a></h2><p>Alternatively, you can do it per <strong>batch</strong>.</p><p>You can select multiple shots or assets by pressing the <strong>ctrl</strong> or <strong>shift</strong> key.</p><p>Then, go to the <strong>Change status</strong> section on the action menu.</p><p><img src="'+rt+'" alt="action menu status"></p><p>Choose the new status for your selected tasks (1). You can also add a comment for all the selected tasks (2) You validate the new status with the <strong>Confirm</strong> button.</p><p><img src="'+pt+'" alt="Change status per batch"><img src="'+lt+'" alt="Metadata Column Sort By"></p><p>The shots are not sorted by name but by the metadata column information.</p><p><img src="'+ct+'" alt="Metadata Column Sort By result"></p><p>You can also select in the menu if you want to edit the name of the metadata column and its information or if you want to delete it.</p><p>You can also use the <strong>CSV Import</strong> to fill your custom metadata column quickly. First, you must create your <strong>Metadata column</strong> into Kitsu, add it to your spreadsheet, and copy-paste your data into the <strong>CSV Import</strong>.</p><p><a href="./../feature/index.html#update-your-shots">Update Shots information with CSV Import</a></p><h1 id="playlists" tabindex="-1">Playlists <a class="header-anchor" href="#playlists" aria-label="Permalink to “Playlists”">​</a></h1><h2 id="create-a-playlist" tabindex="-1">Create a Playlist <a class="header-anchor" href="#create-a-playlist" aria-label="Permalink to “Create a Playlist”">​</a></h2><p>You can find the <strong>Playlists</strong> page on the drop-down menu.</p><p><img src="'+ht+'" alt="Playlist main menu"></p><p>The <strong>playlist</strong> page is separated into two parts:</p><ul><li>(1) The playlist list where you can <strong>create</strong> a playlist or load an existing one.</li><li>(2) The last created playlists and the last modified playlists</li></ul><p><img src="'+mt+'" alt="Playlist page"></p><p>Start by creating a <strong>Playlist</strong><img src="'+dt+'" alt="Playlist add button">. Your default name is the date and the hour. You can change it immediately. You can choose if the playlist will be shared with the <strong>studio</strong> or the <strong>client</strong> and if it&#39;s a <strong>shot</strong> or <strong>asset</strong> playlist. You can also add a <strong>Task Type</strong> tag to the playlist.</p><p><img src="'+gt+'" alt="Playlist add page"></p><p>Once the playlist created, via the search/filter bar, you can select which shots to add to your playlist.</p><p>You can also choose to <strong>add whole movie</strong>, and it will add all the shots of the movie.</p><p>You can select <strong>Daily pending</strong>, which will add all the <strong>WFA</strong> tasks of the day.</p><p>Otherwise, you can <strong>Add the whole sequence</strong> if you want to focus only on a particular sequence.</p><p>You can use the same <strong>filter</strong> than on the global shot/asset page. For example, you can select all the WFA short for the animation stage. You have to type <strong>animation=wfa</strong> in the search bar. Valid your selection with the <strong>Add selection</strong> button. Kitsu will select the shots that have the <strong>WFA</strong> status at the <strong>Animation</strong> stage, but Kitsu will automatically load <strong>the latest uploaded version</strong>.</p><p>The shots appear on the top part of the screen. Every change are automatically saved.</p><p><img src="'+ut+'" alt="Playlist page"></p><h2 id="review-and-validations" tabindex="-1">Review and Validations <a class="header-anchor" href="#review-and-validations" aria-label="Permalink to “Review and Validations”">​</a></h2><p>Once you have created a playlist; you have several options:</p><p><img src="'+wt+'" alt="Playlist Global"></p><ul><li><p>Play or Pause</p></li><li><p>Navigate from element to element</p></li><li><p>See the position of the selected element compare to the total number of elements</p></li><li><p>Mute or unmute the sound</p></li><li><p>Change the speed, double speed (x2), full speed (x1), half of the speed (x0.50), or a quarter of the speed (x0.25)</p></li><li><p>Loop on one element</p></li><li><p>Display the sound wave</p></li><li><p>Display annotations during the play</p></li><li><p>TC of the element compared to the TC of the whole playlist</p></li><li><p>Number of frame</p></li><li><p>Navigate frame per frame on the preview. You can also do it with the arrow on the Keyboard.</p></li><li><p>Compare tool</p></li><li><p>Undo and Redo option for the drawing comment</p></li><li><p>Text and drawing option, and delete selection</p></li><li><p>Change the task type of all the elements of the playlist</p></li><li><p>Display the comment section</p></li><li><p>Hide the elements of the playlist</p></li><li><p>Switch between LD (low definition) to HD (High definition)</p></li><li><p>Download the playlist as a <strong>Zip</strong> files with all the separated elements, a <strong>.csv</strong> text file, or <strong>Build .mp4</strong> to create the whole movie (only for shots)</p></li><li><p>Fullscreen</p></li></ul><p>For each playlisted shot/asset, you can choose the <strong>task</strong> and the <strong>version</strong> you want to see.</p><p><img src="'+yt+'" alt="Playlist task selection"><img src="'+ft+'" alt="Playlist version selection"></p><p>You can also play side by side two tasks of a shot.</p><p>Click on the <strong>Compare</strong> button <img src="'+o+'" alt="Compare button"> and choose the second task type.</p><p><img src="'+bt+'" alt="Playlist side by side"></p><p>The primary purpose of the playlist is to help you with the review of the shots and assets.</p><p>You can comment on the shots directly from the preview.</p><p>Click on the <strong>comment</strong> button.</p><p><img src="'+vt+'" alt="Playlist comment"></p><p>You now have access to the right panel, with all the history of the comments and status.</p><p>You can see the drawing comment on the video (the red dot below the timeline).</p><p><img src="'+_t+'" alt="Playlist comment"></p><p>You can draw or type on the video (same than <a href="./../getting-started-client/index.html#perform-a-review">Perform a review</a>), with the <strong>draw</strong> button <img src="'+a+'" alt="draw button"></p><h2 id="review-room" tabindex="-1">Review Room <a class="header-anchor" href="#review-room" aria-label="Permalink to “Review Room”">​</a></h2><p>On top of the playlist you have a button to <strong>Join Review Room</strong>. The review room will synchronize all the participants.</p><p>Everybody in the review room will see in real time the play and pause, the shots and frame selection.</p><p>The people in the review room will also see the drawing annotation synchronized.</p><p><img src="'+kt+'" alt="Playlist review room"></p><h2 id="batch-upload-previews-as-thumbnails" tabindex="-1">Batch Upload Previews (as Thumbnails) <a class="header-anchor" href="#batch-upload-previews-as-thumbnails" aria-label="Permalink to “Batch Upload Previews (as Thumbnails)”">​</a></h2><p>You can use the <strong>Add Thumbnails</strong> button <img src="'+Pt+'" alt="Add thumbnails button"> on the global page to massively import thumbnails.</p><p><img src="'+Ct+'" alt="History"></p><p>A new pop-up opens and asks you to choose which task types the thumbnails are linked.</p><p><strong>Thumbnails batch import accept images files and video files</strong>.</p><p>For the video files, only the first frame is used as the thumbnail.</p><p>You have to name your thumbnails as sequence_shot.</p>',195)])])}const Ft=s(Tt,[["render",Yt]]);export{$t as __pageData,Ft as default};
